from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from bson import ObjectId
from datetime import datetime
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB", "cms_db")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]

profiles = db["user_profiles"]
documents = db["documents"]

profiles.create_index([("user_id", ASCENDING)], unique=True)
documents.create_index([("owner_id", ASCENDING)])
documents.create_index([("tags", ASCENDING)])
documents.create_index([("created_at", DESCENDING)])


def serialize_doc(doc):
    if not doc:
        return None
    doc["_id"] = str(doc["_id"])
    for k, v in list(doc.items()):
        if isinstance(v, ObjectId):
            doc[k] = str(v)
        elif isinstance(v, datetime):
            doc[k] = v.isoformat()
    return doc


@app.route("/health", methods=["GET"])
def health():
    try:
        client.admin.command("ping")
        return jsonify({"status": "ok"}), 200
    except Exception as e:
        return jsonify({"status": "error", "error": str(e)}), 500


@app.route("/profiles", methods=["POST"])
def create_or_update_profile():
    data = request.get_json(force=True) or {}
    user_id = data.get("user_id")
    if not user_id:
        return jsonify({"error": "user_id is required"}), 400

    profile = {
        "user_id": user_id,
        "name": data.get("name", ""),
        "email": data.get("email", ""),
        "bio": data.get("bio", ""),
        "roles": data.get("roles", []),
        "preferences": data.get("preferences", {}),
        "updated_at": datetime.utcnow(),
    }

    result = profiles.update_one(
        {"user_id": user_id},
        {"$set": profile, "$setOnInsert": {"created_at": datetime.utcnow()}},
        upsert=True,
    )

    saved = profiles.find_one({"user_id": user_id})
    return jsonify({"matched": result.matched_count, "upserted_id": str(result.upserted_id) if result.upserted_id else None, "profile": serialize_doc(saved)}), 200


@app.route("/profiles/<user_id>", methods=["GET"])
def get_profile(user_id):
    profile = profiles.find_one({"user_id": user_id})
    if not profile:
        return jsonify({"error": "profile not found"}), 404
    return jsonify(serialize_doc(profile)), 200


@app.route("/profiles/<user_id>", methods=["DELETE"])
def delete_profile(user_id):
    result = profiles.delete_one({"user_id": user_id})
    if result.deleted_count == 0:
        return jsonify({"error": "profile not found"}), 404
    return jsonify({"deleted": True}), 200


@app.route("/documents", methods=["POST"])
def create_document():
    data = request.get_json(force=True) or {}
    owner_id = data.get("owner_id")
    title = data.get("title")
    content = data.get("content", "")

    if not owner_id or not title:
        return jsonify({"error": "owner_id and title are required"}), 400

    doc = {
        "owner_id": owner_id,
        "title": title,
        "content": content,
        "tags": data.get("tags", []),
        "status": data.get("status", "draft"),
        "metadata": data.get("metadata", {}),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
    }

    result = documents.insert_one(doc)
    saved = documents.find_one({"_id": result.inserted_id})
    return jsonify(serialize_doc(saved)), 201


@app.route("/documents/<doc_id>", methods=["GET"])
def get_document(doc_id):
    try:
        _id = ObjectId(doc_id)
    except Exception:
        return jsonify({"error": "invalid document id"}), 400

    doc = documents.find_one({"_id": _id})
    if not doc:
        return jsonify({"error": "document not found"}), 404
    return jsonify(serialize_doc(doc)), 200


@app.route("/documents/<doc_id>", methods=["PUT"])
def update_document(doc_id):
    try:
        _id = ObjectId(doc_id)
    except Exception:
        return jsonify({"error": "invalid document id"}), 400

    data = request.get_json(force=True) or {}
    update = {
        "updated_at": datetime.utcnow()
    }
    for field in ["title", "content", "tags", "status", "metadata", "owner_id"]:
        if field in data:
            update[field] = data[field]

    result = documents.update_one({"_id": _id}, {"$set": update})
    if result.matched_count == 0:
        return jsonify({"error": "document not found"}), 404

    doc = documents.find_one({"_id": _id})
    return jsonify(serialize_doc(doc)), 200


@app.route("/documents/<doc_id>", methods=["DELETE"])
def delete_document(doc_id):
    try:
        _id = ObjectId(doc_id)
    except Exception:
        return jsonify({"error": "invalid document id"}), 400

    result = documents.delete_one({"_id": _id})
    if result.deleted_count == 0:
        return jsonify({"error": "document not found"}), 404
    return jsonify({"deleted": True}), 200


@app.route("/documents/search", methods=["GET"])
def search_documents():
    owner_id = request.args.get("owner_id")
    tag = request.args.get("tag")
    status = request.args.get("status")
    q = request.args.get("q")

    query = {}
    if owner_id:
        query["owner_id"] = owner_id
    if tag:
        query["tags"] = tag
    if status:
        query["status"] = status
    if q:
        query["$or"] = [
            {"title": {"$regex": q, "$options": "i"}},
            {"content": {"$regex": q, "$options": "i"}},
        ]

    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    cursor = documents.find(query).sort("created_at", DESCENDING).skip(skip).limit(limit)
    results = [serialize_doc(doc) for doc in cursor]
    return jsonify({"count": len(results), "results": results}), 200


@app.route("/documents/aggregate/summary", methods=["GET"])
def aggregate_summary():
    pipeline = [
        {
            "$group": {
                "_id": "$status",
                "count": {"$sum": 1},
                "avg_title_length": {"$avg": {"$strLenCP": "$title"}},
            }
        },
        {
            "$sort": {"count": -1}
        }
    ]
    results = list(documents.aggregate(pipeline))
    for r in results:
        if "_id" in r and isinstance(r["_id"], ObjectId):
            r["_id"] = str(r["_id"])
    return jsonify({"results": results}), 200


@app.route("/documents/aggregate/by-owner", methods=["GET"])
def aggregate_by_owner():
    pipeline = [
        {
            "$group": {
                "_id": "$owner_id",
                "document_count": {"$sum": 1},
                "latest_created_at": {"$max": "$created_at"},
                "statuses": {"$addToSet": "$status"},
            }
        },
        {
            "$sort": {"document_count": -1}
        }
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


@app.route("/documents/aggregate/tags", methods=["GET"])
def aggregate_tags():
    pipeline = [
        {"$unwind": "$tags"},
        {
            "$group": {
                "_id": "$tags",
                "count": {"$sum": 1}
            }
        },
        {"$sort": {"count": -1, "_id": 1}},
        {"$limit": 20}
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


@app.route("/documents/aggregate/recent", methods=["GET"])
def aggregate_recent():
    days = int(request.args.get("days", 30))
    since = datetime.utcnow().timestamp() - (days * 86400)
    since_dt = datetime.utcfromtimestamp(since)

    pipeline = [
        {"$match": {"created_at": {"$gte": since_dt}}},
        {
            "$group": {
                "_id": None,
                "count": {"$sum": 1},
                "owners": {"$addToSet": "$owner_id"},
                "statuses": {"$addToSet": "$status"},
            }
        }
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"results": results}), 200


@app.route("/documents/bulk", methods=["POST"])
def bulk_insert_documents():
    data = request.get_json(force=True) or {}
    items = data.get("documents", [])
    if not isinstance(items, list) or not items:
        return jsonify({"error": "documents must be a non-empty list"}), 400

    now = datetime.utcnow()
    docs = []
    for item in items:
        owner_id = item.get("owner_id")
        title = item.get("title")
        if not owner_id or not title:
            return jsonify({"error": "each document requires owner_id and title"}), 400
        docs.append({
            "owner_id": owner_id,
            "title": title,
            "content": item.get("content", ""),
            "tags": item.get("tags", []),
            "status": item.get("status", "draft"),
            "metadata": item.get("metadata", {}),
            "created_at": item.get("created_at", now),
            "updated_at": now,
        })

    result = documents.insert_many(docs)
    return jsonify({"inserted_count": len(result.inserted_ids), "inserted_ids": [str(i) for i in result.inserted_ids]}), 201


